import { Link, NavLink } from 'react-router-dom';
import useAxios from 'axios-hooks';
import '../App.css';
import { Component } from 'react';
import '../../node_modules/bootstrap/dist/css/bootstrap.css'
import BootstrapTable from 'react-bootstrap-table-next';

const columns =[{
    dataField: 'id',
    text: 'ID'
},{
    dataField: 'name_sing',
    text: 'Название знака'
}];

const const_data = []

const Sings = () => {
    const [{ data, loading, error }, refetch] = useAxios('http://127.0.0.1:5000/sings');

    if (loading) {
        return(
            <div className='loading'>
                <p>Загрузка данных...</p>
            </div>
        );
    }

    if (error) {
        return(
            <div className='error'>
                <p>Ошибка:</p>
                <p>{error.message}</p>
                <button onClick={() => refetch()}>
                    Повторный запрос
                </button>
            </div>
        );
    }

    return (
        <div className="users-container">
        <h1>Список пользователей</h1>

        <button onClick={() => refetch()} className="refresh-btn">
            Обновить данные
        </button>

        {data && data.length > 0 ? (
            <table className="users-table">
            <thead>
                <tr>
                <th>ID</th>
                <th>Название дорожного знака</th>
                </tr>
            </thead>
            <tbody>
                {data.map(user => (
                <tr key={user.id}>
                    <td>{user.name_sing}</td>
                </tr>
                ))}
            </tbody>
            </table>
        ) : (
            <p>Нет данных для отображения</p>
        )}
        </div>
    );
    };

